rule.example:
import kotlinx.coroutines.GlobalScope
import kotlinx.coroutines.launch

class Bad {
    fun bad(t: Thread) {
        t.run() // violation: runs in the current thread, not a new one
    }
}

class Good {
    fun good(t: Thread) {
        t.start() // ok: starts a new OS thread
    }

    fun goodKotlin() {
        GlobalScope.launch { /* ... */ } // ok: idiomatic Kotlin coroutine
    }
}

import java.util.HashMap
import java.util.concurrent.ConcurrentHashMap

class Bad {
    private val map: HashMap<String, Int> = HashMap() // violation: not thread-safe as a field
}

class Good {
    private val map = ConcurrentHashMap<String, Int>() // ok: thread-safe

    fun localOnly() {
        val local: HashMap<String, Int> = HashMap() // ok: local variable, not a field
    }
}

class Bad {
    fun bad(lock: Any) {
        synchronized(lock) {
            lock.notify() // violation: may miss waiting threads
        }
    }
}

class Good {
    fun good(lock: Any) {
        synchronized(lock) {
            lock.notifyAll() // ok: wakes all waiting threads
        }
    }
}
